from __future__ import annotations

import pytest
from starter_challenge.examples.median_price_tracker import MedianPriceTracker
from starter_challenge.examples.sqft_price_tracker import SqftPriceTracker


SAMPLE_FEATURES = {
    "living_area_sqft": 1800.0,
    "lot_size_sqft": 7000.0,
    "bedrooms": 3,
    "bathrooms": 2.0,
    "year_built": 2000,
    "latitude": 33.749,
    "longitude": -84.388,
    "has_garage": True,
    "has_pool": False,
}

EMPTY_FEATURES = {}


@pytest.fixture(
    params=[
        MedianPriceTracker,
        SqftPriceTracker,
    ]
)
def tracker(request):
    """Parametrize over all example trackers."""
    return request.param()


class TestExampleContract:
    """Every example must satisfy the tournament prediction contract."""

    def test_returns_dict_with_predicted_price(self, tracker):
        result = tracker.predict(SAMPLE_FEATURES)
        assert isinstance(result, dict)
        assert "predicted_price" in result
        assert isinstance(result["predicted_price"], (int, float))

    def test_predicted_price_is_non_negative(self, tracker):
        result = tracker.predict(SAMPLE_FEATURES)
        assert result["predicted_price"] >= 0.0


class TestMedianPriceTracker:
    """MedianPriceTracker always returns $350,000."""

    def test_always_returns_median(self):
        tracker = MedianPriceTracker()
        result = tracker.predict(SAMPLE_FEATURES)
        assert result["predicted_price"] == 350000.0

    def test_ignores_features(self):
        tracker = MedianPriceTracker()
        result = tracker.predict(EMPTY_FEATURES)
        assert result["predicted_price"] == 350000.0


class TestSqftPriceTracker:
    """SqftPriceTracker predicts based on living area."""

    def test_price_based_on_sqft(self):
        tracker = SqftPriceTracker()
        result = tracker.predict(SAMPLE_FEATURES)
        assert result["predicted_price"] == 1800.0 * 200

    def test_zero_sqft_returns_zero(self):
        tracker = SqftPriceTracker()
        result = tracker.predict({"living_area_sqft": 0.0})
        assert result["predicted_price"] == 0.0

    def test_missing_sqft_returns_zero(self):
        tracker = SqftPriceTracker()
        result = tracker.predict(EMPTY_FEATURES)
        assert result["predicted_price"] == 0.0

"""Tests for TrackerBase — property price prediction interface."""

from __future__ import annotations

import pytest
from starter_challenge.tracker import TrackerBase


class DummyTracker(TrackerBase):
    """Minimal implementation for testing."""

    def predict(self, features: dict) -> dict:
        sqft = features.get("living_area_sqft", 0.0)
        return {"predicted_price": sqft * 100}


class TestPredictInterface:
    """predict() receives a single feature dict, returns a prediction dict."""

    def test_returns_dict(self):
        tracker = DummyTracker()
        result = tracker.predict({"living_area_sqft": 1500.0})
        assert isinstance(result, dict)
        assert "predicted_price" in result

    def test_processes_features(self):
        tracker = DummyTracker()
        result = tracker.predict({"living_area_sqft": 2000.0})
        assert result["predicted_price"] == 200000.0

    def test_empty_features(self):
        tracker = DummyTracker()
        result = tracker.predict({})
        assert result["predicted_price"] == 0.0


class TestPredictBase:
    def test_not_implemented_on_base(self):
        tracker = TrackerBase()
        with pytest.raises(NotImplementedError):
            tracker.predict({"living_area_sqft": 1500.0})
